// Neon Timetable — Build Order
//
// LANGUAGE:  Kotlin
// UI:        Jetpack Compose (declarative)
// STORAGE:   SharedPreferences + JSON (no server needed)
// REMINDERS: AlarmManager + Notifications
//
// FEATURES & HOW THEY LINK:
//   Theme ........ colours every card & bar
//   Period ....... one class block (subject, time, room)
//   Break/Lunch .. a 'breakbar' between periods
//   Day View ..... shows periods + breakbars in time order
//   Add Period ... form -> creates a Period -> saved
//   Homework ..... attached to a Period, has a due date
//   Reminder ..... fires a notification before due date
//
// app/src/main/java/com/example/timetable/
//   MainActivity.kt        <- app entry
//   models/Models.kt       <- Period, Break, Homework
//   data/Storage.kt        <- save & load
//   ui/TimetableScreen.kt  <- the day view
//   ui/AddPeriodDialog.kt  <- the add form
//   reminder/Reminder.kt   <- schedules notifications

@Composable
fun PeriodCard(period: Period, onClick: () -> Unit) {
    val accent = period.accentColor()
    Surface(
        onClick = onClick,                       // <- hook for 'add homework' later
        shape = RoundedCornerShape(16.dp),        // rounded box
        color = Theme.surface,
        border = BorderStroke(1.dp, accent),      // glowing outline
        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp)
    ) {
        Row(Modifier.height(IntrinsicSize.Min)) {
            Box(Modifier.width(4.dp).fillMaxHeight().background(accent)) // left stripe
            Column(Modifier.padding(12.dp)) {
                Text(period.subject, color = Theme.textMain,
                     fontWeight = FontWeight.Bold, fontSize = 16.sp)
                Text("${period.startTime}–${period.endTime}  •  ${period.room}",
                     color = Theme.textDim, fontSize = 13.sp)
            }
        }
    }
}

@Composable
fun BreakBar(brk: Break) {
    val fill = if (brk.isLunch) Theme.gold.copy(alpha = 0.18f)
               else Theme.border
    val label = if (brk.isLunch) Theme.gold else Theme.textDim
    Surface(
        shape = RoundedCornerShape(10.dp),
        color = fill,
        modifier = Modifier.fillMaxWidth().padding(vertical = 2.dp)
    ) {
        Row(
            Modifier.fillMaxWidth().padding(horizontal = 12.dp, vertical = 6.dp),
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Text(brk.label.uppercase(), color = label,
                 fontWeight = FontWeight.Medium, fontSize = 13.sp)
            Text("${brk.startTime}–${brk.endTime}",
                 color = Theme.textDim, fontSize = 12.sp)
        }
    }
}

// One list that can hold either type:
sealed interface DayItem {
    val startTime: String
    data class P(val period: Period) : DayItem { override val startTime get() = period.startTime }
    data class B(val brk: Break)     : DayItem { override val startTime get() = brk.startTime }
}

@Composable
fun TimetableScreen(periods: List<Period>, breaks: List<Break>, onAdd: () -> Unit) {
    val items = (periods.map { DayItem.P(it) } + breaks.map { DayItem.B(it) })
        .sortedBy { it.startTime }          // <- the timeline is always correct

    Box(Modifier.fillMaxSize().background(Theme.background)) {
        LazyColumn(Modifier.padding(12.dp)) {
            items(items) { item ->
                when (item) {
                    is DayItem.P -> PeriodCard(item.period) { /* add homework (Step 8) */ }
                    is DayItem.B -> BreakBar(item.brk)
                }
            }
        }
        FloatingActionButton(onClick = onAdd,
            containerColor = Theme.sky,
            modifier = Modifier.align(Alignment.BottomEnd).padding(16.dp)) {
            Text("+", fontSize = 24.sp)
        }
    }
}

@Composable
fun AddPeriodDialog(day: Int, onSave: (Period) -> Unit, onDismiss: () -> Unit) {
    var subject by remember { mutableStateOf("") }
    var start by remember { mutableStateOf("") }
    var end by remember { mutableStateOf("") }
    var room by remember { mutableStateOf("") }
    var accent by remember { mutableStateOf(0) }

    AlertDialog(
        onDismissRequest = onDismiss,
        containerColor = Theme.surface,
        title = { Text("Add period", color = Theme.textMain) },
        text = {
            Column {
                DarkField("Subject", subject) { subject = it }
                DarkField("Start (07:15)", start) { start = it }
                DarkField("End (08:00)", end) { end = it }
                DarkField("Room", room) { room = it }
                Row { Theme.accents.forEachIndexed { i, c ->
                    ColorDot(c, selected = i == accent) { accent = i } } }
            }
        },
        confirmButton = { TextButton(onClick = {
            onSave(Period(UUID.randomUUID().toString(), subject, start, end, room, day, accent))
            onDismiss()
        }) { Text("Save", color = Theme.sky) } },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel", color = Theme.textDim) } }
    )
}

class TimetableStorage(context: Context) {
    private val prefs = context.getSharedPreferences("timetable", Context.MODE_PRIVATE)
    private val gson = Gson()

    fun savePeriods(list: List<Period>) {
        prefs.edit().putString("periods", gson.toJson(list)).apply()
    }
    fun loadPeriods(): List<Period> {
        val json = prefs.getString("periods", null) ?: return emptyList()
        val type = object : TypeToken<List<Period>>() {}.type
        return gson.fromJson(json, type)
    }

    fun saveBreaks(list: List<Break>) {
        prefs.edit().putString("breaks", gson.toJson(list)).apply()
    }
    fun loadBreaks(): List<Break> {
        val json = prefs.getString("breaks", null) ?: return emptyList()
        val type = object : TypeToken<List<Break>>() {}.type
        return gson.fromJson(json, type)
    }
}

