var dueMillis by remember { mutableStateOf(0L) }
val ctx = LocalContext.current

fun openDatePicker() {
    val now = Calendar.getInstance()
    DatePickerDialog(ctx, { _, y, m, d ->
        val c = Calendar.getInstance().apply { set(y, m, d, 8, 0, 0) }
        dueMillis = c.timeInMillis            // <- epoch millis the reminder will use
    }, now.get(Calendar.YEAR), now.get(Calendar.MONTH), now.get(Calendar.DAY_OF_MONTH)).show()
}

TextButton(onClick = { openDatePicker() }) {
    val label = if (dueMillis == 0L) "Pick due date"
                else "Due: " + SimpleDateFormat("d MMM", Locale.getDefault()).format(Date(dueMillis))
    Text(label, color = Theme.gold)
}

class ReminderScheduler(private val ctx: Context) {
    fun schedule(homework: Homework, subject: String) {
        val triggerTime = homework.dueDate - 24L * 60 * 60 * 1000   // 1 day before
        if (triggerTime < System.currentTimeMillis()) return        // already too late

        val intent = Intent(ctx, ReminderReceiver::class.java).apply {
            putExtra("title", homework.title)
            putExtra("subject", subject)
        }
        val pi = PendingIntent.getBroadcast(
            ctx, homework.id.hashCode(), intent,            // <- unique per homework
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT)

        val am = ctx.getSystemService(Context.ALARM_SERVICE) as AlarmManager
        am.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerTime, pi)
    }
}

class ReminderReceiver : BroadcastReceiver() {
    override fun onReceive(ctx: Context, intent: Intent) {
        val title = intent.getStringExtra("title") ?: "Homework"
        val subject = intent.getStringExtra("subject") ?: ""

        val mgr = ctx.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        if (Build.VERSION.SDK_INT >= 26) {
            mgr.createNotificationChannel(
                NotificationChannel("homework", "Homework reminders",
                    NotificationManager.IMPORTANCE_HIGH))
        }
        val notif = NotificationCompat.Builder(ctx, "homework")
            .setSmallIcon(R.drawable.ic_book)
            .setContentTitle("$subject homework due tomorrow")
            .setContentText(title)
            .setAutoCancel(true)
            .build()
        NotificationManagerCompat.from(ctx).notify(title.hashCode(), notif)
    }
}

