// AFTER: turn "HH:mm" into minutes-since-midnight, then sort by the number
fun String.toMinutes(): Int {
    val parts = this.split(":")
    val h = parts[0].trim().toIntOrNull() ?: 0
    val m = parts.getOrNull(1)?.trim()?.toIntOrNull() ?: 0
    return h * 60 + m
}

