@OptIn(ExperimentalFoundationApi::class)
@Composable
fun WeekScreen(allPeriods: List<Period>, allBreaks: List<Break>, onAdd: (Int) -> Unit) {
    val days = listOf("Mon","Tue","Wed","Thu","Fri","Sat","Sun")
    val pager = rememberPagerState(pageCount = { 7 })

    Column(Modifier.background(Theme.background)) {
        Row { days.forEachIndexed { i, d ->
            Text(d, color = if (i == pager.currentPage) Theme.sky else Theme.textDim,
                 modifier = Modifier.padding(12.dp)) } }
        HorizontalPager(state = pager) { day ->
            val p = allPeriods.filter { it.day == day }
            val b = allBreaks.filter { it.day == day }
            if (p.isEmpty() && b.isEmpty())
                EmptyDay()                       // friendly 'tap + to start'
            else
                DayList(p, b) { onAdd(day) }
        }
    }
}

fun deletePeriod(periodId: String) {
    // 3) the homework attached to this period (linked by periodId)
    val attached = allHomework.filter { it.periodId == periodId }

    // 2) cancel each one's reminder (linked by homework id)
    attached.forEach { hw ->
        val intent = Intent(ctx, ReminderReceiver::class.java)
        val pi = PendingIntent.getBroadcast(ctx, hw.id.hashCode(), intent,
            PendingIntent.FLAG_IMMUTABLE)
        (ctx.getSystemService(Context.ALARM_SERVICE) as AlarmManager).cancel(pi)
    }

    // 1) now remove the data, top of the chain to the bottom
    storage.saveHomework(allHomework - attached.toSet())
    storage.savePeriods(allPeriods.filter { it.id != periodId })
    // period -> homework -> reminders : delete walks the links backwards
}

